SELECT customer_id, customer_unique_id, customer_city, customer_state
FROM customers
LIMIT 10;

SELECT product_id, product_category_name, product_name_lenght, product_weight_g
FROM products
LIMIT 20;

SELECT ROUND(AVG(order_total_value)::numeric, 2) AS average_order_value
FROM (
    SELECT oi.order_id, SUM(oi.price + oi.freight_value) AS order_total_value
    FROM order_items oi
    GROUP BY oi.order_id
) AS order_values;
